setup:
# --- grid helper (hidden) — truth table built from YOUR circuits ---
# Over all 8 three-input rows it calls the student's own mux(a,b,c) and
# majority(a,b,c). A finished circuit lights its square; an unfinished or wrong
# one shows '?'. The input columns and header always render (never blank).
# Returns {grid, caption}: the caption is the readable legend (shown below).
def __cell(name, args, color):
    fn = globals().get(name)
    if fn is None:
        return "?"
    try:
        v = fn(*args)
    except Exception:
        return "?"
    if v == 1:
        return color
    if v == 0:
        return ""
    return "?"

def __grid():
    rows = [["A", "B", "C", "M", "V"]]
    for a in (0, 1):
        for b in (0, 1):
            for c in (0, 1):
                rows.append([
                    str(a), str(b), str(c),
                    __cell("mux", [a, b, c], "blue"),
                    __cell("majority", [a, b, c], "green"),
                ])
    return {
        "grid": rows,
        "caption": "M = MUX (blue): outputs A when C=0, B when C=1 (C is the selector). V = MAJORITY (green): lights when at least two of A, B, C are 1. A ? means that circuit isn't finished yet.",
    }
